import{_ as a,o as t,c as o,a2 as s}from"./chunks/framework.BYlK8ftn.js";const u=JSON.parse('{"title":"World-map & fast-travel overlay — UX spec","description":"","frontmatter":{},"headers":[],"relativePath":"guide/world-map-overlay-ux.md","filePath":"guide/world-map-overlay-ux.md","lastUpdated":1782031862000}'),n={name:"guide/world-map-overlay-ux.md"};function r(l,e,i,d,c,p){return t(),o("div",null,[...e[0]||(e[0]=[s(`<h1 id="world-map-fast-travel-overlay-—-ux-spec" tabindex="-1">World-map &amp; fast-travel overlay — UX spec <a class="header-anchor" href="#world-map-fast-travel-overlay-—-ux-spec" aria-label="Permalink to &quot;World-map &amp; fast-travel overlay — UX spec&quot;">​</a></h1><p>The UX/IA reference for the <strong>world-map / fast-travel overlay</strong> (E3.1-UX, <a href="/korovany/plan/game-plan">FLO-331</a>). This is the design-side companion to <a href="./world-map">World map &amp; zones</a>, which documents the zone registry and the <code>planTravel</code> data flow. Read that first for the model; this doc owns the <strong>interaction design, wireframes, states, layout, tokens, and accessibility</strong>.</p><blockquote><p><strong>Status — documents shipped reality.</strong> The overlay was implemented in FLO-332 (PR #46) and FLO-390 as <code>src/components/WorldMap.tsx</code>. This spec is the canonical UX source of truth: it both specifies the design and records a design review of the shipped component, with the one craft gap fixed in the same change (see <a href="#design-review-of-the-shipped-overlay">Design review</a>).</p></blockquote><hr><h2 id="_1-job-to-be-done" tabindex="-1">1. Job-to-be-done <a class="header-anchor" href="#_1-job-to-be-done" aria-label="Permalink to &quot;1. Job-to-be-done&quot;">​</a></h2><blockquote><p><em>&quot;I&#39;m done in this zone — take me to another part of the world without making me walk there, and don&#39;t let a stray click teleport me by accident.&quot;</em></p></blockquote><p>The overlay is a <strong>modal travel picker</strong>, not a strategic map. It answers three questions at a glance (Recognition over Recall, Information Scent):</p><ol><li><strong>Where am I now?</strong> → current-zone marker.</li><li><strong>Where can I go?</strong> → available zones, clearly separated from locked ones.</li><li><strong>What happens if I pick one?</strong> → a deliberate two-step confirm before travel.</li></ol><p>Scope is intentionally small (Occam&#39;s Razor): four zones, no pan/zoom, no routes. A spatial/illustrated map is a future delighter (Kano), not a must-have.</p><hr><h2 id="_2-information-architecture" tabindex="-1">2. Information architecture <a class="header-anchor" href="#_2-information-architecture" aria-label="Permalink to &quot;2. Information architecture&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart TD</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  HUD[&quot;Live play (HUD)&quot;] --&gt;|&quot;Travel button / press M&quot;| Overlay[&quot;World-map overlay (modal)&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  Overlay --&gt;|&quot;select available zone&quot;| Confirm[&quot;Confirm row: Travel to {zone}?&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  Confirm --&gt;|&quot;Travel&quot;| Loading[&quot;Travelling… (scene streams)&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  Confirm --&gt;|&quot;Cancel&quot;| Overlay</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  Loading --&gt;|&quot;scene ready&quot;| Zone[&quot;Destination zone (overlay closed)&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  Loading --&gt;|&quot;load failed&quot;| Error[&quot;Error: Travel failed — Try again&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  Error --&gt;|&quot;re-select zone&quot;| Confirm</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  Overlay --&gt;|&quot;✕ / Esc / M&quot;| HUD</span></span></code></pre></div><p><strong>Zone taxonomy</strong> (from the registry — game-plan §0):</p><table tabindex="0"><thead><tr><th>Id</th><th>Display name</th><th>Lore name</th><th>Owner</th><th>Travel status</th></tr></thead><tbody><tr><td><code>human-lands</code></td><td>Human lands</td><td>The Salt Road of Velya</td><td>Neutral</td><td>available</td></tr><tr><td><code>forest</code></td><td>Forest</td><td>The Emerald Thicket of Lysaen</td><td>Forest Elves</td><td>available</td></tr><tr><td><code>empire</code></td><td>Empire</td><td>The Imperial March</td><td>The Emperor</td><td>locked</td></tr><tr><td><code>mountains</code></td><td>Mountains</td><td>Black Crown Pass</td><td>The Villain</td><td>available</td></tr></tbody></table><p>Display order is fixed (registry order) so the grid is spatially stable between opens (Jakob&#39;s Law — the map never reshuffles under the player&#39;s muscle memory).</p><hr><h2 id="_3-layout-1280×800-laptop" tabindex="-1">3. Layout (1280×800 laptop) <a class="header-anchor" href="#_3-layout-1280×800-laptop" aria-label="Permalink to &quot;3. Layout (1280×800 laptop)&quot;">​</a></h2><p>A centered modal over a dimmed scrim, never full-bleed — the player stays oriented in the world behind it (the live scene shows through the 60%-opacity scrim). Single panel, <code>min(48rem, 100vw − 2rem)</code> wide, capped to the viewport height. The four zones sit in a <strong>2×2 grid</strong> (<code>grid-template-columns: repeat(2, 1fr)</code>), which keeps every card a comfortable click target and avoids a tall single-column list on a wide laptop (Fitts&#39;s Law, F-pattern scan).</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌──────────────────────── scrim (rgba(6,10,14,.6)) ───────────────────────┐</span></span>
<span class="line"><span>│                                                                          │</span></span>
<span class="line"><span>│        ┌──────────────────── worldmap-panel ────────────────────┐       │</span></span>
<span class="line"><span>│        │  World map                                        [ ✕ ] │ ← header</span></span>
<span class="line"><span>│        │                                                         │       │</span></span>
<span class="line"><span>│        │  ┌───────────────────────┐  ┌───────────────────────┐  │       │</span></span>
<span class="line"><span>│        │  │ Human lands           │  │ Forest                │  │       │</span></span>
<span class="line"><span>│        │  │ The Salt Road of Velya│  │ The Emerald Thicket…  │  │       │</span></span>
<span class="line"><span>│        │  │ Neutral               │  │ Forest Elves          │  │       │</span></span>
<span class="line"><span>│        │  │ [ YOU ARE HERE ]      │  │                       │  │ ← 2×2  │</span></span>
<span class="line"><span>│        │  └───────────────────────┘  └───────────────────────┘  │   grid │</span></span>
<span class="line"><span>│        │  ┌───────────────────────┐  ┌───────────────────────┐  │       │</span></span>
<span class="line"><span>│        │  │ Empire        (dimmed)│  │ Mountains     (dimmed)│  │       │</span></span>
<span class="line"><span>│        │  │ The Imperial March    │  │ Black Crown Pass      │  │       │</span></span>
<span class="line"><span>│        │  │ The Emperor           │  │ The Villain           │  │       │</span></span>
<span class="line"><span>│        │  │ [ LOCKED ]            │  │ [ LOCKED ]            │  │       │</span></span>
<span class="line"><span>│        │  └───────────────────────┘  └───────────────────────┘  │       │</span></span>
<span class="line"><span>│        │                                                         │       │</span></span>
<span class="line"><span>│        │  Select a zone to travel.                               │ ← footer</span></span>
<span class="line"><span>│        └─────────────────────────────────────────────────────────┘       │</span></span>
<span class="line"><span>│                                                                          │</span></span>
<span class="line"><span>└──────────────────────────────────────────────────────────────────────────┘</span></span></code></pre></div><p>Each <strong>zone card</strong> is one button (the whole card is the hit target — Fitts) with a three-line stack: <strong>display name</strong> (primary, 1.05rem/700), <strong>lore name</strong> (secondary, sage <code>#c7d2a2</code>), <strong>owner</strong> (tertiary, 75% opacity), plus an optional status pill. The footer is a <strong>single live region</strong> that swaps between hint / confirm / loading / error — one fixed slot (<code>min-height: 2.75rem</code>) so the panel never reflows as state changes (no layout jump = Doherty/perceived stability).</p><hr><h2 id="_4-states-all-five-with-wireframes" tabindex="-1">4. States (all five, with wireframes) <a class="header-anchor" href="#_4-states-all-five-with-wireframes" aria-label="Permalink to &quot;4. States (all five, with wireframes)&quot;">​</a></h2><p>The overlay must render every state with equal care — a beautiful happy path with a raw empty/error state is a broken product.</p><h3 id="a-·-default-no-selection" tabindex="-1">A · Default (no selection) <a class="header-anchor" href="#a-·-default-no-selection" aria-label="Permalink to &quot;A · Default (no selection)&quot;">​</a></h3><p>Current zone carries the green <strong>YOU ARE HERE</strong> pill and is non-selectable (<code>is-current</code>, disabled). Locked zones are dimmed (opacity .5) with a red <strong>LOCKED</strong> pill and are non-selectable. Footer hint: <em>&quot;Select a zone to travel.&quot;</em></p><h3 id="b-·-selected-→-two-step-confirm" tabindex="-1">B · Selected → two-step confirm <a class="header-anchor" href="#b-·-selected-→-two-step-confirm" aria-label="Permalink to &quot;B · Selected → two-step confirm&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>│  ┌ Human lands ─┐  ┌ Forest ════════┐  ← selected: gold border + gold-tint fill</span></span>
<span class="line"><span>│  │ YOU ARE HERE │  │ (is-selected)  │</span></span>
<span class="line"><span>│  └──────────────┘  └────────────────┘</span></span>
<span class="line"><span>│  ┌ Empire LOCKED┐  ┌ Mountains LOCK ┐</span></span>
<span class="line"><span>│  └──────────────┘  └────────────────┘</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>│  Travel to Forest?   [ Travel ]  [ Cancel ]   ← primary | secondary</span></span></code></pre></div><p>Selecting an available zone highlights it (gold <code>#f7d774</code> border + tint) and replaces the footer hint with a <strong>confirm row</strong>: prompt + a <strong>primary</strong> <code>Travel</code> button and a <strong>secondary</strong> <code>Cancel</code>. This two-step gate (Forgiveness / error prevention — Nielsen #5) means a stray click only <em>selects</em>; travel always takes a second, deliberate confirm. <code>Cancel</code> returns to the default footer with the selection cleared.</p><p><strong>Primary vs secondary must be visually unambiguous</strong> (Von Restorff, visible hierarchy): <code>Travel</code> is a solid gold button (<code>#f7d774</code> fill, dark <code>#1a1206</code> text); <code>Cancel</code> is the ghost/secondary style. See the design-review fix below.</p><h3 id="c-·-loading-travel-in-progress" tabindex="-1">C · Loading (travel in progress) <a class="header-anchor" href="#c-·-loading-travel-in-progress" aria-label="Permalink to &quot;C · Loading (travel in progress)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>│  …all four zone cards disabled (dimmed, not-allowed)…</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>│  Travelling…                                  ← status, no spinner-of-doom</span></span></code></pre></div><p>On confirm, every zone card disables (<code>busy</code>) so the player can&#39;t queue a second travel mid-stream, and the footer shows <em>&quot;Travelling…&quot;</em>. Target is the Doherty threshold; if streaming can exceed ~400ms, the implementer should add a subtle indeterminate progress affordance (skeleton/animated ellipsis) — text-only is acceptable for the current short hops but should not regress on heavier zones.</p><h3 id="d-·-error-load-failed" tabindex="-1">D · Error (load failed) <a class="header-anchor" href="#d-·-error-load-failed" aria-label="Permalink to &quot;D · Error (load failed)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>│  …zones re-enabled, last selection still highlighted…</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>│  Travel failed — the zone could not be loaded. Try again.   ← role=&quot;alert&quot;, salmon</span></span></code></pre></div><p>Failure re-enables the cards and shows a salmon <code>role=&quot;alert&quot;</code> message (<code>#e0817a</code>/<code>#f3b0a8</code> family). Recovery is <strong>forgiving</strong>: the player re-selects the zone to get the confirm row again. <em>Copy note:</em> &quot;Try again&quot; currently implies a button that isn&#39;t literally present — recovery is re-selecting the card. Keep the copy honest or add a literal <strong>Retry</strong> button in the confirm slot (tracked as a follow-up, not blocking).</p><h3 id="e-·-empty-no-zones-registered" tabindex="-1">E · Empty (no zones registered) <a class="header-anchor" href="#e-·-empty-no-zones-registered" aria-label="Permalink to &quot;E · Empty (no zones registered)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>│  No zones are available to travel to yet.</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>│  Select a zone to travel.</span></span></code></pre></div><p>Defensive state for a registry with zero zones (should not occur in normal play, but the component handles it). Plain, calm copy — no error styling, because an empty registry is not the player&#39;s fault.</p><hr><h2 id="_5-tokens" tabindex="-1">5. Tokens <a class="header-anchor" href="#_5-tokens" aria-label="Permalink to &quot;5. Tokens&quot;">​</a></h2><p>Korovany has <strong>no CSS-variable token layer yet</strong> — colours are inlined per component but drawn from a consistent de-facto palette established by the menu &amp; HUD (<code>src/styles/global.css</code>). The overlay reuses that palette; the table below names the values so handoff is unambiguous. <em>System recommendation: promote these to CSS custom properties (<code>--accent-gold</code>, <code>--text-primary</code>, …) in a future pass so the overlay, menu, and HUD share one source — out of scope here, noted for the design system.</em></p><table tabindex="0"><thead><tr><th>Role</th><th>Value</th><th>Used for</th></tr></thead><tbody><tr><td>Scrim</td><td><code>rgba(6,10,14,.6)</code></td><td>overlay backdrop</td></tr><tr><td>Panel bg</td><td><code>rgba(10,16,20,.9)</code></td><td>modal surface</td></tr><tr><td>Panel border</td><td><code>rgba(255,255,255,.18)</code></td><td>modal edge</td></tr><tr><td>Accent gold</td><td><code>#f7d774</code></td><td>selection, hover, focus, primary button</td></tr><tr><td>Primary text on gold</td><td><code>#1a1206</code></td><td><code>Travel</code> button label</td></tr><tr><td>Text primary</td><td><code>#f8fafc</code></td><td>zone names, controls</td></tr><tr><td>Text secondary (lore)</td><td><code>#c7d2a2</code></td><td>lore subtitle</td></tr><tr><td>Text muted</td><td><code>#d9e3ea</code> / 75% opacity</td><td>owner line, hints</td></tr><tr><td>Success</td><td><code>rgba(120,200,120,*)</code></td><td>YOU ARE HERE pill</td></tr><tr><td>Danger</td><td><code>rgba(200,120,120,*)</code></td><td>LOCKED pill</td></tr><tr><td>Error text</td><td><code>#f3b0a8</code></td><td>travel-failed alert</td></tr><tr><td>Radius</td><td><code>8px</code> panel · <code>6px</code> cards/buttons · <code>999px</code> pills</td><td>—</td></tr><tr><td>Card gap</td><td><code>0.75rem</code></td><td>grid gutter</td></tr><tr><td>Panel padding</td><td><code>1.5rem</code></td><td>—</td></tr></tbody></table><p>Spacing uses the existing <code>rem</code> rhythm (<code>0.2 / 0.35 / 0.75 / 1.25 / 1.5rem</code>); no new one-off values were introduced.</p><hr><h2 id="_6-interaction-input" tabindex="-1">6. Interaction &amp; input <a class="header-anchor" href="#_6-interaction-input" aria-label="Permalink to &quot;6. Interaction &amp; input&quot;">​</a></h2><ul><li><strong>Open:</strong> HUD <strong>Travel</strong> button, or press <strong>M</strong> during live play.</li><li><strong>Close:</strong> <strong>✕</strong> button, <strong>Esc</strong>, or <strong>M</strong> again — all return to live play without travelling (multiple exits = Nielsen #3 user control / Forgiveness).</li><li><strong>Select:</strong> click/tap a zone card, or keyboard-focus + Enter/Space.</li><li><strong>Confirm:</strong> <code>Travel</code> commits; <code>Cancel</code> clears the selection.</li><li><strong>Disabled targets:</strong> current zone and locked zones are <code>disabled</code> + <code>aria-disabled</code> and never receive selection.</li></ul><hr><h2 id="_7-accessibility-wcag-pour" tabindex="-1">7. Accessibility (WCAG POUR) <a class="header-anchor" href="#_7-accessibility-wcag-pour" aria-label="Permalink to &quot;7. Accessibility (WCAG POUR)&quot;">​</a></h2><ul><li><strong>Role/modality:</strong> <code>role=&quot;dialog&quot;</code>, <code>aria-modal=&quot;true&quot;</code>, <code>aria-labelledby=&quot;worldmap-title&quot;</code>. The panel is the labelled dialog.</li><li><strong>Live region:</strong> the footer is <code>aria-live=&quot;polite&quot;</code>; the error uses <code>role=&quot;alert&quot;</code> so failures are announced.</li><li><strong>State, not just colour:</strong> selection carries <code>aria-pressed</code>; disabled carries <code>aria-disabled</code>; current/locked status is conveyed by the <strong>text pill</strong>, not colour alone (colour-independence — a colour-blind player still reads &quot;YOU ARE HERE&quot; / &quot;LOCKED&quot;).</li><li><strong>Focus:</strong> <code>:focus-visible</code> gets the same gold ring as hover; targets are full cards / ≥2.5rem buttons (touch &amp; motor accessibility).</li><li><strong>Contrast:</strong> gold-on-dark and light-text-on-panel clear AA for the text sizes used; the <code>Travel</code> primary uses dark text on gold for AA on the fill.</li><li><strong>Reduced motion:</strong> the overlay currently uses no transitions; if a fade-in is added later, gate it behind <code>prefers-reduced-motion: reduce</code>.</li></ul><hr><h2 id="_8-design-review-of-the-shipped-overlay" tabindex="-1">8. Design review of the shipped overlay <a class="header-anchor" href="#_8-design-review-of-the-shipped-overlay" aria-label="Permalink to &quot;8. Design review of the shipped overlay&quot;">​</a></h2><p>Rendered <code>WorldMap.tsx</code> + its real CSS at <strong>1280×800</strong> (default, confirm, and error states). Verdict: <strong>solid visual craft — coherent with the menu palette, clear hierarchy, all five states handled.</strong> One concrete gap, fixed in this change:</p><ul><li><strong>FIXED — primary action had no emphasis.</strong> The confirm row&#39;s <code>Travel</code> button used a <code>.primary-action</code> class that was <strong>undefined in CSS</strong>, so <code>Travel</code> and <code>Cancel</code> rendered at identical weight — the player couldn&#39;t tell the primary action at a glance (fails the &quot;primary visible in two seconds&quot; bar; Von Restorff). Added a <code>.primary-action</code> rule (solid gold fill, dark label) so the commit action visually dominates <code>Cancel</code>. CSS only; no behaviour change.</li></ul><p>Non-blocking follow-ups (logged for the owning engineer, not gating this spec):</p><ul><li><strong>Error &quot;Try again&quot; wording vs affordance</strong> — copy implies a button; recovery is re-selecting the card. Either soften the copy or add a literal <strong>Retry</strong> in the confirm slot (state D).</li><li><strong>Loading affordance on heavy zones</strong> — text-only &quot;Travelling…&quot; is fine for current short hops; revisit with a progress/skeleton cue if zone streaming can exceed the Doherty ~400ms threshold (state C).</li><li><strong>Token layer</strong> — promote the inlined palette to CSS custom properties shared with the menu/HUD (system-level, §5).</li></ul><hr><h2 id="_9-acceptance-for-the-implemented-overlay" tabindex="-1">9. Acceptance (for the implemented overlay) <a class="header-anchor" href="#_9-acceptance-for-the-implemented-overlay" aria-label="Permalink to &quot;9. Acceptance (for the implemented overlay)&quot;">​</a></h2><ul><li>[x] All four zones listed as travel targets, in stable registry order.</li><li>[x] Current-zone indicator (YOU ARE HERE) + available vs locked distinction, conveyed by text pill (not colour alone).</li><li>[x] Two-step select → confirm/cancel travel affordance.</li><li>[x] Empty / loading / error states all handled and styled.</li><li>[x] Usable at 1280×800; reuses visual-language v1.2 palette.</li><li>[x] Primary <code>Travel</code> action visually dominant over <code>Cancel</code> (this change).</li></ul>`,58)])])}const g=a(n,[["render",r]]);export{u as __pageData,g as default};
